import{_ as t,o as a,c as o,ao as s}from"./chunks/framework.Ch3FBIWy.js";const g=JSON.parse('{"title":"Developer Guide","description":"","frontmatter":{},"headers":[],"relativePath":"developer.md","filePath":"developer.md","lastUpdated":null}'),r={name:"developer.md"};function i(n,e,d,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="Developer-Guide" tabindex="-1">Developer Guide <a class="header-anchor" href="#Developer-Guide" aria-label="Permalink to &quot;Developer Guide {#Developer-Guide}&quot;">​</a></h1><p>This page is for people working <strong>on</strong> PureSparse (contributors), not people using it. It covers the repository layout, how to build and test, and the non-negotiable disciplines — clean-room provenance, the wall-time performance gate, trim compatibility, and the StrictMode guarantee gates — that every change must respect. The authoritative, always-current version of these rules lives in the repository&#39;s <code>CLAUDE.md</code>; the full architecture is in <code>docs/design.md</code> (and <code>docs/design_qr*.md</code>, <code>docs/design_gpu.md</code> for the QR and GPU milestones).</p><h2 id="Repository-layout" tabindex="-1">Repository layout <a class="header-anchor" href="#Repository-layout" aria-label="Permalink to &quot;Repository layout {#Repository-layout}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Path</th><th style="text-align:right;">What lives there</th></tr></thead><tbody><tr><td style="text-align:right;"><code>src/ordering/</code></td><td style="text-align:right;">Fill-reducing orderings: AMD (<code>amd.jl</code>), COLAMD (<code>colamd.jl</code>), the AᵀA/star-pattern builders</td></tr><tr><td style="text-align:right;"><code>src/symbolic/</code></td><td style="text-align:right;">Elimination tree, postorder, column counts, supernode amalgamation — the analyze phase</td></tr><tr><td style="text-align:right;"><code>src/numeric/</code></td><td style="text-align:right;">Supernodal LLᵀ (<code>llt.jl</code>), LDLᵀ (<code>ldlt.jl</code>), the panel solve (<code>solve.jl</code>)</td></tr><tr><td style="text-align:right;"><code>src/simplicial/</code></td><td style="text-align:right;">Simplicial LDLᵀ + rank-1 update/downdate</td></tr><tr><td style="text-align:right;"><code>src/qr/</code></td><td style="text-align:right;">Sparse QR: <code>symbolic.jl</code>/<code>numeric.jl</code> (<code>:column</code>, left-looking) and <code>frontal_*.jl</code> (<code>:frontal</code>, multifrontal-WY), plus <code>solve.jl</code>/<code>frontal_solve.jl</code></td></tr><tr><td style="text-align:right;"><code>src/contracts.jl</code></td><td style="text-align:right;">TypeContracts.jl compile-time interface contracts (eliminated by the trimmer)</td></tr><tr><td style="text-align:right;"><code>src/strict.jl</code></td><td style="text-align:right;">The runtime StrictMode check layer (input-shape / finiteness guards), gated by <code>checks_enabled()</code></td></tr><tr><td style="text-align:right;"><code>src/tuning.jl</code></td><td style="text-align:right;">Compile-time, Preferences-backed tuning constants (no runtime CPU detection — trim rule)</td></tr><tr><td style="text-align:right;"><code>ext/PureSparseCUDAExt.jl</code> + <code>ext/*.jl</code></td><td style="text-align:right;">The CUDA weak-dependency GPU backend (pure KernelAbstractions kernels)</td></tr><tr><td style="text-align:right;"><code>juliac/</code></td><td style="text-align:right;">The <code>juliac --trim=safe</code> smoke build (<code>build.jl</code>, <code>entry.jl</code>)</td></tr><tr><td style="text-align:right;"><code>test/</code></td><td style="text-align:right;">ReTestItems <code>@testitem</code>s, one file per module</td></tr><tr><td style="text-align:right;"><code>benchmark/</code></td><td style="text-align:right;">Chairmarks harness + the GPU probes; results saved to <code>benchmark/results/*.json</code> (gitignored)</td></tr><tr><td style="text-align:right;"><code>docs/design*.md</code></td><td style="text-align:right;">The design documents (in-repo, not published); every large change starts here</td></tr></tbody></table><p>Dense per-supernode / per-front kernels (<code>potrf!</code>, <code>trsm!</code>, <code>syrk!</code>, <code>gemm!</code>, <code>geqrf!</code>, WY apply) are called <strong>exclusively through <a href="https://github.com/el-oso/PureBLAS.jl" target="_blank" rel="noreferrer">PureBLAS.jl</a></strong> — never reimplemented in <code>src/</code>, never routed to OpenBLAS/LAPACK directly.</p><h2 id="Building-and-testing" tabindex="-1">Building and testing <a class="header-anchor" href="#Building-and-testing" aria-label="Permalink to &quot;Building and testing {#Building-and-testing}&quot;">​</a></h2><p>PureSparse uses <strong><a href="https://github.com/JuliaTesting/ReTestItems.jl" target="_blank" rel="noreferrer">ReTestItems.jl</a></strong>; each test is a self-contained <code>@testitem</code> that can be run individually.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># full suite (the pre-merge / release gate) — from the package project:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">julia </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">project</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">. </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;using Pkg; Pkg.test()&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a single item, while iterating (filtered by name):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">julia </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">project</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">test </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;using ReTestItems, PureSparse; runtests(PureSparse; name=&quot;qr! refactor&quot;)&#39;</span></span></code></pre></div><p>Run the whole suite only as a <strong>gate</strong> — iterate with a filtered subset (<code>name=</code>). The suite is CPU-only; the GPU backend is exercised separately (see <em>GPU backend</em> below).</p><div class="warning custom-block"><p class="custom-block-title">Use <code>Pkg.test()</code>, not a bare <code>--project=test</code> run</p><p><code>test/Manifest.toml</code> is gitignored and can drift from the package&#39;s compat bounds. A direct <code>julia --project=test …</code> activates that (possibly stale) manifest and can fail with <em>&quot;can not merge projects&quot;</em>. <code>Pkg.test()</code> re-resolves a fresh environment and is the supported entry point; run <code>Pkg.update(...)</code> on <code>--project=test</code> if you want the local test manifest synced for filtered runs.</p></div><p><strong>Correctness oracles.</strong> Every numeric path is checked three ways: a dense <code>BigFloat</code> factorization on small/medium matrices (exact comparison), residual gates on the SuiteSparse Matrix Collection zoo, and <code>SparseArrays</code>&#39; own factorization (CHOLMOD / SuiteSparseQR) as a <strong>black-box</strong> cross-check of the <em>output</em> (never its source — see <em>Clean-room provenance</em>).</p><p><strong>Zero-allocation gate.</strong> <code>cholesky!</code>/<code>ldlt!</code>/<code>qr!</code>/<code>solve!</code> on an existing factor must be <code>@allocated == 0</code>. This is tested with StrictMode checks <strong>disabled</strong> (the runtime check layer in <code>src/strict.jl</code> allocates by design and must not be conflated with the gate — see below).</p><h2 id="Clean-room-provenance-absolute" tabindex="-1">Clean-room provenance (absolute) <a class="header-anchor" href="#Clean-room-provenance-absolute" aria-label="Permalink to &quot;Clean-room provenance (absolute) {#Clean-room-provenance-absolute}&quot;">​</a></h2><p><strong>This is the rule most easily violated by accident.</strong> CHOLMOD&#39;s Supernodal/Modify modules and SuiteSparseQR are GPL. Design and all code derive <strong>only</strong> from published papers, official user-guide documentation, and independent reasoning. Never read CHOLMOD/SuiteSparse source in any form — not on GitHub, not from search snippets, not from model recall of source text, not via a third-party port derived from it. Every identifier and numeric constant must survive <em>&quot;where did this come from?&quot;</em> with a paper/user-guide citation or an in-repo derivation — a name or number that &quot;happens to match&quot; CHOLMOD&#39;s is a defect (this caught two real coincidences during review). Black-box comparison against CHOLMOD/SPQR <strong>output</strong> (via <code>SparseArrays</code>) is fine and used throughout. <code>faer</code> (Rust, MIT) and <code>PureKLU.jl</code> (MIT) are readable references. See <a href="./provenance">Provenance &amp; Licensing</a> and <code>docs/design.md</code> §11.</p><h2 id="Performance-discipline" tabindex="-1">Performance discipline <a class="header-anchor" href="#Performance-discipline" aria-label="Permalink to &quot;Performance discipline {#Performance-discipline}&quot;">​</a></h2><ul><li><p><strong>The gate is wall-time, not GFlops.</strong> <code>median_seconds(PureSparse+PureBLAS) &lt; median_seconds(CHOLMOD+OpenBLAS)</code>, both under each solver&#39;s own ordering <strong>and</strong> under an identical <code>GivenOrdering</code> permutation (the latter isolates factorization throughput from ordering quality). GFlops is a secondary diagnostic only (it is gameable by a higher-fill ordering).</p></li><li><p><strong>Analyze once, factorize many.</strong> <code>Symbolic</code> is immutable and shared by reference; <code>cholesky!</code>/ <code>ldlt!</code>/<code>qr!</code> on an existing factor never recompute ordering/etree/supernodes. This is the primary API principle (the target user — interior-point optimizers — refactorizes the same pattern hundreds of times per solve).</p></li><li><p><strong>Generic over <code>T&lt;:Number</code> / <code>Ti&lt;:Integer</code> on hot paths</strong> (one implementation, no per-type duplication, AD-traceable). <code>Float64</code> is the tuned path; other <code>T</code> are correct-but-generic.</p></li><li><p><strong>Measure on a warm session.</strong> Julia JIT-compiles per concrete-type specialization, so the first call pays a compile tax. Warm up, then benchmark with Chairmarks (single-thread pinned, median not min, locked clock). Results are saved to <code>benchmark/results/*.json</code> first; <strong>plots (violins) regenerate from the saved JSON</strong> — never re-run a benchmark to redraw a plot.</p></li></ul><h2 id="Correctness-and-performance-guarantees-StrictMode-TypeContracts" tabindex="-1">Correctness &amp; performance guarantees (StrictMode + TypeContracts) <a class="header-anchor" href="#Correctness-and-performance-guarantees-StrictMode-TypeContracts" aria-label="Permalink to &quot;Correctness &amp; performance guarantees (StrictMode + TypeContracts) {#Correctness-and-performance-guarantees-StrictMode-TypeContracts}&quot;">​</a></h2><p>Two <strong>separate</strong> mechanisms, easy to conflate:</p><ul><li><p><strong>TypeContracts.jl</strong> (<code>src/contracts.jl</code>) — compile-time interface contracts, precompile-time only, eliminated by the trimmer. Never a runtime mechanism.</p></li><li><p><strong>StrictMode.jl</strong> (<code>src/strict.jl</code>) — a runtime pre/post-condition layer (shape, nnz, finiteness guards) gated behind <code>StrictMode.checks_enabled()</code>. These checks may allocate; they are for debugging, not the hot path, and are <strong>off</strong> in the perf/zero-alloc configuration.</p></li></ul><p>On top of that, PureSparse runs <strong>StrictMode <code>@assert_*</code> guarantee gates</strong> in <code>test/strictmode_guarantees_tests.jl</code>:</p><ul><li><p><code>@assert_concurrency_safe cholesky/ldlt(sym, A)</code> — machine-proof that the allocating factor treats its <code>Symbolic</code> argument read-only, i.e. one immutable <code>Symbolic</code> is safe to share by reference across concurrent factorizations (the analyze-once thesis).</p></li><li><p><code>@assert_typestable solve!(...)</code> — concrete return type + no internal instability, all factor kinds.</p></li></ul><p>These macros require checks <strong>on</strong> (<code>assert_enabled()</code> ⇒ <code>checks_enabled()</code>), which conflicts with the checks-off zero-alloc gate — so they run in an <strong>isolated subprocess</strong> with its own <code>[StrictMode] checks_enabled = true</code> preference plus <code>AllocCheck</code>/<code>JET</code>, and they target only <strong>check-free</strong> functions (<code>solve!</code> and the constructors), so the analyzed body equals the shipped one. When adding such a guarantee, keep this constraint in mind: asserting on a function that calls <code>src/strict.jl</code> checks would analyze a checks-on body that is not what ships.</p><h2 id="Trim-compatibility" tabindex="-1">Trim compatibility <a class="header-anchor" href="#Trim-compatibility" aria-label="Permalink to &quot;Trim compatibility {#Trim-compatibility}&quot;">​</a></h2><p>PureSparse must build a factor-and-solve entry point under <code>juliac --trim=safe</code>: no runtime <code>eval</code>/<code>invokelatest</code>, no <code>Vector{Any}</code> on hot paths, no runtime CPU-feature detection (tuning constants are compile-time <code>Preferences</code>-backed consts). Two layers check this:</p><ul><li><p>The in-suite <code>TrimCheck.@validate</code> (<code>test/trim_tests.jl</code>) — a static reachability scan over <strong>positional-argument</strong> roots (<code>cholesky!</code>/<code>ldlt!</code>/<code>qr!</code>/<code>solve!</code>). It cannot express keyword-argument construction entries.</p></li><li><p>The real end-to-end build:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">julia juliac</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jl          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># builds juliac/build/puresparse_smoke via --trim=safe</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">./</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">juliac</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">puresparse_smoke </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># exit 0 + small residuals ⇒ pass</span></span></code></pre></div><p>Run this before a release — it is the only gate that exercises the actual smoke path in <code>juliac/entry.jl</code> (including keyword-argument entries the in-suite scan can&#39;t reach). Return types on the hot paths must be <strong>concrete</strong>; an abstract inferred return boxes the value and breaks trim resolution downstream.</p></li></ul><h2 id="GPU-backend" tabindex="-1">GPU backend <a class="header-anchor" href="#GPU-backend" aria-label="Permalink to &quot;GPU backend {#GPU-backend}&quot;">​</a></h2><p>The GPU code is a <strong>CUDA weak-dependency extension</strong> (<code>ext/</code>), loaded only when the user has <code>CUDA.jl</code>. Its kernels are <strong>pure KernelAbstractions</strong> (portable to AMD/Intel), and on Float64 they match or beat cuSOLVER/cuBLAS on the crown fronts (see <a href="./benchmarking">Benchmarking</a>); the vendor libraries are used only as reference/comparison arms. GPU work is validated on a machine with a CUDA device — the CPU test suite does not require one.</p><h2 id="Proposing-a-larger-change" tabindex="-1">Proposing a larger change <a class="header-anchor" href="#Proposing-a-larger-change" aria-label="Permalink to &quot;Proposing a larger change {#Proposing-a-larger-change}&quot;">​</a></h2><p>Non-trivial features follow the repository&#39;s design process, visible in <code>docs/design*.md</code>: write a design document, subject it to <strong>independent adversarial review</strong> (a second model/reviewer, blind where possible), fold every finding into a v2, and only then implement — task by task, each landing with its oracle tests before the next. Milestones that turn on an unproven performance bet are <strong>measured first</strong> with a cheap probe before any production code (the GPU-QR milestone, M7, was shelved this way — its probes are in <code>benchmark/gpu/qr_*phase0.jl</code> and the verdict in <code>docs/design_qr_gpu.md</code>). Delegate genuinely hard algorithmic pieces (AMD&#39;s degree bookkeeping, Davis–Hager update recurrences) rather than approximating them from memory — approximation risks both correctness bugs and clean-room violations.</p><h2 id="Cutting-a-release" tabindex="-1">Cutting a release <a class="header-anchor" href="#Cutting-a-release" aria-label="Permalink to &quot;Cutting a release {#Cutting-a-release}&quot;">​</a></h2><p>PureSparse depends on other Pure-ecosystem packages (<code>PureBLAS</code>, <code>StrictMode</code>, <code>TypeContracts</code>), so releases are <strong>dependency-ordered</strong>: those must be registered in General before PureSparse can register. The typical flow: run the full suite and the <code>juliac</code> smoke build as gates, pin the <code>[compat]</code> bounds to the versions you will register, tag <code>vX.Y.Z</code>, then register once the dependency chain is in General.</p>`,31)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
